# --- Smart step with conditional logic ---
@when('I open Guest browsing mode')
def step_open_guest_mode(context):
    """
    Smart step that handles different UI states for opening Guest mode.
    This step will:
    1. First click the Profile button
    2. Try to find and click "Browse as guest" button directly
    3. If not found, click "Other profiles" then "Browse as Guest"
    """
    # First click the Profile button
    result = call_tool_sync(
        context,
        context.session.call_tool(
            name='click_element',
            arguments={
                'caller': 'behave-automation',
                'locator_strategy': 'AppiumBy.NAME',
                'locator_value': 'Profile 1 Profile, Please sign in',
                'need_snapshot': 0,
            },
        ),
    )
    result_json = get_tool_json(result)
    assert result_json.get('status') == 'success', (
        f"Expected status to be 'success', got '{result_json.get('status')}', error: '{result_json.get('error')}'"
    )

    # Try to find "Browse as guest" button directly
    try:
        result = call_tool_sync(
            context,
            context.session.call_tool(
                name='find_element',
                arguments={
                    'caller': 'behave-automation',
                    'locator_strategy': 'AppiumBy.NAME',
                    'locator_value': 'Browse as guest',
                    'need_snapshot': 0,
                },
            ),
        )
        result_json = get_tool_json(result)

        if result_json.get('status') == 'success':
            # Direct path: Click "Browse as guest" button
            logging.info("Found 'Browse as guest' button directly, clicking it")
            result = call_tool_sync(
                context,
                context.session.call_tool(
                    name='click_element',
                    arguments={
                        'caller': 'behave-automation',
                        'locator_strategy': 'AppiumBy.NAME',
                        'locator_value': 'Browse as guest',
                        'need_snapshot': 0,
                    },
                ),
            )
            result_json = get_tool_json(result)
            assert result_json.get('status') == 'success', (
                f"Expected status to be 'success', got '{result_json.get('status')}', error: '{result_json.get('error')}'"
            )
        else:
            raise Exception('Browse as guest button not found directly')

    except Exception as e:
        # Fallback path: Click "Other profiles" then "Browse as Guest"
        logging.info(
            "'Browse as guest' button not found directly, using 'Other profiles' path"
        )

        result = call_tool_sync(
            context,
            context.session.call_tool(
                name='click_element',
                arguments={
                    'caller': 'behave-automation',
                    'locator_strategy': 'AppiumBy.NAME',
                    'locator_value': 'Other profiles',
                    'need_snapshot': 0,
                },
            ),
        )
        result_json = get_tool_json(result)
        assert result_json.get('status') == 'success', (
            f"Expected status to be 'success', got '{result_json.get('status')}', error: '{result_json.get('error')}'"
        )

        # Then click "Browse as Guest"
        result = call_tool_sync(
            context,
            context.session.call_tool(
                name='click_element',
                arguments={
                    'caller': 'behave-automation',
                    'locator_strategy': 'AppiumBy.NAME',
                    'locator_value': 'Browse as Guest',
                    'need_snapshot': 0,
                },
            ),
        )
        result_json = get_tool_json(result)
        assert result_json.get('status') == 'success', (
            f"Expected status to be 'success', got '{result_json.get('status')}', error: '{result_json.get('error')}'"
        )


